#include <bits/stdc++.h>
using namespace std;
int n,m;
long long f[12][1<<11];
bool check(int x,int y){
	if(x&y)
		return false;
	int z=x|y,sum=0;
	for(int i=0;i<m;i++){
		if(z&(1<<i)){
			if(sum%2)
				return false;
			sum=0;
		}else
			sum++;
	}
	if(sum%2)
		return false;
	return true;
}
int main(){
	while(scanf("%d%d",&n,&m)){
		if(!n && !m)
			break;
		if(n*m%2){
			printf("0\n");
			continue;
		}
		memset(f,0,sizeof(f));
		f[0][0]=1;
		for(int i=1;i<=n;i++)
			for(int j=0;j<1<<m;j++)
				for(int k=0;k<1<<m;k++)
					if(check(j,k))
						f[i][j]+=f[i-1][k];
		printf("%lld\n",f[n][0]);
	}
	return 0;
}
